(function () {
  function ready(fn) {
    if (document.readyState !== "loading") {
      fn();
      return;
    }
    document.addEventListener("DOMContentLoaded", fn, { once: true });
  }

  function debounce(fn, delay) {
    var timer;
    return function () {
      window.clearTimeout(timer);
      timer = window.setTimeout(fn, delay);
    };
  }

  ready(function () {
    var nav = document.getElementById("site-nav");
    if (nav) {
      var button = nav.querySelector("button");
      var visibleLinks = nav.querySelector(".visible-links");
      var hiddenLinks = nav.querySelector(".hidden-links");
      var breaks = [];

      function updateNav() {
        if (!button || !visibleLinks || !hiddenLinks) return;

        var availableSpace = button.classList.contains("hidden")
          ? nav.clientWidth
          : nav.clientWidth - button.offsetWidth - 30;

        if (visibleLinks.scrollWidth > availableSpace && visibleLinks.lastElementChild) {
          breaks.push(visibleLinks.scrollWidth);
          hiddenLinks.insertBefore(visibleLinks.lastElementChild, hiddenLinks.firstElementChild);
          button.classList.remove("hidden");
        } else if (breaks.length && availableSpace > breaks[breaks.length - 1]) {
          visibleLinks.appendChild(hiddenLinks.firstElementChild);
          breaks.pop();
        }

        button.setAttribute("count", breaks.length);
        button.classList.toggle("hidden", breaks.length < 1);
        hiddenLinks.classList.toggle("hidden", breaks.length < 1);

        if (visibleLinks.scrollWidth > availableSpace && visibleLinks.children.length > 1) {
          updateNav();
        }
      }

      button.classList.add("hidden");
      button.addEventListener("click", function (event) {
        event.preventDefault();
        hiddenLinks.classList.toggle("hidden");
        button.classList.toggle("close");
      });
      updateNav();
      window.addEventListener("resize", debounce(updateNav, 100));
    }

    var authorButton = document.querySelector(".author__urls-wrapper button");
    var authorUrls = document.querySelector(".author__urls");

    function syncAuthorUrls() {
      if (!authorUrls || !authorButton) return;
      var buttonVisible = window.getComputedStyle(authorButton).display !== "none";
      var open = authorButton.classList.contains("open");
      authorUrls.style.display = buttonVisible && !open ? "none" : "";
    }

    if (authorButton && authorUrls) {
      authorButton.setAttribute("type", "button");
      authorButton.addEventListener("click", function () {
        authorButton.classList.toggle("open");
        syncAuthorUrls();
      });
      syncAuthorUrls();
      window.addEventListener("resize", debounce(syncAuthorUrls, 100));
    }

    document.addEventListener("click", function (event) {
      var link = event.target.closest && event.target.closest("a[href^='#']");
      if (!link || link.hash.length < 2) return;

      var target = document.getElementById(decodeURIComponent(link.hash.slice(1)));
      if (!target) return;

      event.preventDefault();
      target.scrollIntoView({ behavior: "smooth", block: "start" });
      history.pushState(null, "", link.hash);
    });
  });
})();
